// ─── PROFILE AVATAR HELPER ────────────────────────────────────────────────────
const ProfileAvatar = ({ role, color, size = 36 }) => {
  if (role === "admin") {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    const ctx = useAdminProfile();
    if (ctx?.profilePhoto) {
      return (
        <div style={{ width: size, height: size, borderRadius: "50%", overflow: "hidden", flexShrink: 0, border: `2px solid ${color}` }}>
          <img src={ctx.profilePhoto} alt="Profile" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
        </div>
      );
    }
    const name = ctx?.profileName || ROLE_USERS[role];
    return <Avatar name={name} color={color} size={size} />;
  }
  return <Avatar name={ROLE_USERS[role]} color={color} size={size} />;
};

// ─── SIDEBAR ──────────────────────────────────────────────────────────────────
export const Sidebar = ({ role, active, onNav, onLogout }) => {
  const items = SIDEBARS[role] || [];
  const color = ROLE_COLORS[role];
  const adminCtx   = role === "admin" ? useAdminProfile() : null; // eslint-disable-line react-hooks/rules-of-hooks
  const displayName = (role === "admin" && adminCtx?.profileName) ? adminCtx.profileName : ROLE_USERS[role];

  return (
    <aside style={{ width: 240, background: T.bg2, borderRight: `1px solid ${T.border}`, display: "flex", flexDirection: "column", position: "fixed", top: 0, bottom: 0, left: 0, zIndex: 200, overflowY: "auto" }}>
      {/* Logo */}
      <div style={{ padding: "18px 20px 14px", borderBottom: `1px solid ${T.border}` }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, fontFamily: "Syne", fontSize: 17, fontWeight: 900 }}>
          <div style={{ width: 34, height: 34, background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16 }}>🎓</div>
          <span>Zenelait<span style={{ color: T.accent }}>LMS</span></span>
        </div>
      </div>

      {/* User Info */}
      <div style={{ padding: "14px 20px", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", gap: 12 }}>
        <ProfileAvatar role={role} color={color} size={36} />
        <div>
          <div style={{ fontSize: 13, fontWeight: 700, lineHeight: 1.3 }}>{displayName}</div>
          <div style={{ fontSize: 11, color: T.muted, marginTop: 1 }}>{ROLE_NAMES[role]}</div>
        </div>
      </div>

      {/* Navigation */}
      <nav style={{ flex: 1, padding: "10px 0" }}>
        {items.map((item, i) => item.section ? (
          <div key={i} style={{ padding: "8px 20px 4px", fontSize: 9, fontWeight: 800, color: T.muted, textTransform: "uppercase", letterSpacing: 1.4 }}>{item.section}</div>
        ) : (
          <div key={item.key} onClick={() => onNav(item.key)}
            style={{
              display: "flex", alignItems: "center", gap: 12, padding: "9px 20px", cursor: "pointer", transition: "all .2s",
              borderLeft: active === item.key ? `3px solid ${color}` : "3px solid transparent",
              background:  active === item.key ? `${color}15` : "transparent",
              color:       active === item.key ? color : T.muted,
              fontWeight:  active === item.key ? 700 : 500, fontSize: 13,
            }}
            onMouseEnter={e => { if (active !== item.key) { e.currentTarget.style.background = `${color}08`; e.currentTarget.style.color = T.text; } }}
            onMouseLeave={e => { if (active !== item.key) { e.currentTarget.style.background = "transparent"; e.currentTarget.style.color = T.muted; } }}
          >
            <span style={{ fontSize: 15 }}>{item.icon}</span>
            <span style={{ flex: 1 }}>{item.label}</span>
            {item.badge && <span style={{ background: T.accentR, color: "#fff", borderRadius: 50, fontSize: 10, fontWeight: 800, padding: "1px 7px" }}>{item.badge}</span>}
          </div>
        ))}
      </nav>

      {/* Logout */}
      <div style={{ padding: "14px 20px", borderTop: `1px solid ${T.border}` }}>
        <button onClick={onLogout}
          style={{ display: "flex", alignItems: "center", gap: 10, fontSize: 13, color: T.muted, background: "none", border: "none", cursor: "pointer", transition: "color .2s" }}
          onMouseEnter={e => e.currentTarget.style.color = T.accentR}
          onMouseLeave={e => e.currentTarget.style.color = T.muted}
        >🚪 Logout</button>
      </div>
    </aside>
  );
};

// ─── DASHBOARD HEADER ─────────────────────────────────────────────────────────
export const DashHeader = ({ role, page, onNav }) => {
  const color = ROLE_COLORS[role];
  const adminCtx    = role === "admin" ? useAdminProfile() : null; // eslint-disable-line react-hooks/rules-of-hooks
  const displayName = (role === "admin" && adminCtx?.profileName) ? adminCtx.profileName : ROLE_USERS[role];

  return (
    <header style={{ position: "fixed", top: 0, left: 240, right: 0, height: 60, background: "rgba(6,4,15,.9)", backdropFilter: "blur(20px)", borderBottom: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 24px", zIndex: 100 }}>
      <div>
        <div style={{ fontSize: 16, fontWeight: 800, fontFamily: "Syne" }}>{page}</div>
        <div style={{ fontSize: 11, color: T.muted }}>Home / {page}</div>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        {["🔔", "🔍"].map((icon, i) => (
          <div key={i}
            style={{ width: 36, height: 36, borderRadius: 9, background: T.bg3, border: `1px solid ${T.border}`, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", fontSize: 15, transition: "all .2s" }}
            onMouseEnter={e => e.currentTarget.style.borderColor = color}
            onMouseLeave={e => e.currentTarget.style.borderColor = T.border}
          >{icon}</div>
        ))}
        <div style={{ display: "flex", alignItems: "center", gap: 10, cursor: "pointer" }} onClick={() => onNav("profile")}>
          <ProfileAvatar role={role} color={color} size={34} />
          <div>
            <div style={{ fontSize: 13, fontWeight: 700 }}>{displayName}</div>
            <div style={{ fontSize: 10, color: T.muted }}>{ROLE_NAMES[role]}</div>
          </div>
        </div>
      </div>
    </header>
  );
};

